//! Eval harness: load YAML cases, score parsed expressions against soft expectations.
//!
//! The `baml_client` module is generated by BAML (`baml-cli generate` from repo root)
//! and enabled with the `llm` feature. Default builds use a small stub so coverage and dry-run
//! tooling do not require generated BAML sources or `protoc`.

pub mod baml_client;

mod correction;
pub mod coverage;

