/// OpenRouter’s OpenAI-compatible HTTP API (`/v1/chat/completions` and related).
///
/// All Plasm `openai-generic` BAML clients and all runtime [`baml::ClientRegistry`] builds use this
/// base URL — traffic is always routed through OpenRouter; the `--model` id is the OpenRouter model slug.
pub const OPENROUTER_OPENAI_COMPAT_BASE_URL: &str = "https://openrouter.ai/api/v1";

/// Default `temperature` for OpenRouter-backed eval / REPL (`TranslatePlan`) — comparable runs.
pub const DEFAULT_OPENROUTER_EVAL_TEMPERATURE: f64 = 0.0;
/// Default `seed` on the OpenRouter request (best-effort reproducibility where the upstream honors it).
pub const DEFAULT_OPENROUTER_EVAL_SEED: u64 = 42;

/// Build options for [`baml::ClientRegistry::add_llm_client`] with provider `openai-generic` → OpenRouter.
///
/// `plasm-eval` and the REPL register the primary client dynamically at runtime (model + key + sampling).
/// Static `baml_src/clients.baml` entries use the same pattern for named clients.
/// Build one `TranslatePlan` user turn: on the **first** turn of a session, embed the full schema
/// bundle plus goal and correction JSON; later turns carry only goal + correction (schema stays in
/// earlier transcript turns).
pub fn nl_translate_user_bundle(
    first_turn: bool,
    schema_context: &str,
    goal: &str,
    correction: &str,
) -> String {
    if first_turn {
        format!("{schema_context}\n--- GOAL ---\n{goal}\n--- CORRECTION FEEDBACK ---\n{correction}")
    } else {
        format!("--- GOAL ---\n{goal}\n--- CORRECTION FEEDBACK ---\n{correction}")
    }
}

pub fn openrouter_eval_llm_options(
    model: &str,
    api_key: &str,
    temperature: f64,
    seed: u64,
) -> HashMap<String, serde_json::Value> {
    [
        (
            "base_url".to_string(),
            serde_json::json!(OPENROUTER_OPENAI_COMPAT_BASE_URL),
        ),
        ("model".to_string(), serde_json::json!(model)),
        ("api_key".to_string(), serde_json::json!(api_key)),
        ("temperature".to_string(), serde_json::json!(temperature)),
        ("seed".to_string(), serde_json::json!(seed)),
    ]
    .into_iter()
    .collect()
}

/// One eval case (YAML).
#[derive(Debug, Clone, Deserialize)]
pub struct EvalCase {
    pub id: String,
    /// Schema directory path (often `apis/<name>`)
    pub schema: String,
    pub goal: String,
    #[serde(default)]
    pub tags: Vec<String>,
    /// Which [`EvalFormId`] buckets this case is intended to cover (for `plasm-eval coverage`).
    #[serde(default)]
    pub covers: Vec<String>,
    /// Optional ground-truth Plasm expression (parse/typecheck check; future: vs LLM output).
    #[serde(default)]
    pub reference_expr: Option<String>,
    pub expect: ExpectBlock,
}

/// Optional scoring weights for correction pipeline (YAML: `expect.correction`).
#[derive(Debug, Clone, Deserialize)]
pub struct CorrectionExpect {
    /// Weight for [`CorrectionMetrics::pipeline_score`] when blending into final `score` (0..=1).
    #[serde(default = "default_correction_weight")]
    pub weight: f32,
}

fn default_correction_weight() -> f32 {
    0.25
}

impl Default for CorrectionExpect {
    fn default() -> Self {
        Self {
            weight: default_correction_weight(),
        }
    }
}

#[derive(Debug, Clone, Deserialize, Default)]
pub struct ExpectBlock {
    /// Any primary entity from any accepted expression may match one of these.
    #[serde(default)]
    pub entities_any: Vec<String>,
    /// Predicate field names that should appear somewhere (soft).
    #[serde(default)]
    pub pred_fields_any: Vec<String>,
    /// Enum/string values that must appear in predicates when present (soft).
    #[serde(default)]
    pub pred_values_any: Vec<String>,
    /// If set, chain steps must include this selector (e.g. `species`).
    #[serde(default)]
    pub chain_selectors_any: Vec<String>,
    /// Projection must be a superset of this (if expression has projection).
    #[serde(default)]
    pub projection_contains: Vec<String>,
    #[serde(default)]
    pub min_steps: Option<usize>,
    #[serde(default)]
    pub max_steps: Option<usize>,
    /// Blend semantic score with correction `pipeline_score` (`weight` toward pipeline).
    #[serde(default)]
    pub correction: CorrectionExpect,
    /// When non-empty, the **final successful** plan’s step text must contain **at least one** of
    /// these substrings (e.g. `"<<"` to require a structured heredoc opener).
    #[serde(default)]
    pub step_text_contains_any: Vec<String>,
}

#[derive(Debug, Clone, Default, serde::Serialize, serde::Deserialize)]
pub struct CaseScore {
    pub id: String,
    pub tags: Vec<String>,
    /// Natural-language goal from the eval case (for reports).
    #[serde(default)]
    pub goal: String,
    /// Optional ground-truth expression from YAML (for diffing in reports).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub reference_expr: Option<String>,
    /// Each LLM round: BAML steps (`text` + `reasoning`) and validation outcome.
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub attempt_trace: Vec<correction::EvalAttemptReport>,
    pub parse_ok: bool,
    pub typecheck_ok: bool,
    pub entity_match: bool,
    pub pred_fields_match: bool,
    pub pred_values_match: bool,
    pub chain_match: bool,
    pub projection_match: bool,
    pub steps_ok: bool,
    /// Final score (semantic blended with correction pipeline when `correction` is set).
    pub score: f32,
    /// Semantic-only score from [`score_case`] before correction blend (if applicable).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub semantic_score: Option<f32>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub correction_pipeline_score: Option<f32>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub correction: Option<CorrectionMetrics>,
    pub notes: Vec<String>,
}

pub fn load_cases_file(path: &Path) -> anyhow::Result<Vec<EvalCase>> {
    let text = std::fs::read_to_string(path)?;
    if let Ok(list) = serde_yaml::from_str::<Vec<EvalCase>>(&text) {
        return Ok(list);
    }
    let single: EvalCase = serde_yaml::from_str(&text)?;
    Ok(vec![single])
}

pub fn load_cases_dir(dir: &Path) -> anyhow::Result<Vec<EvalCase>> {
    let mut out = Vec::new();
    for entry in std::fs::read_dir(dir)? {
        let entry = entry?;
        let p = entry.path();
        if p.file_name()
            .and_then(|n| n.to_str())
            .is_some_and(|n| n == "coverage.yaml" || n == "coverage.yml")
        {
            continue;
        }
        if p.extension()
            .map(|e| e == "yaml" || e == "yml")
            .unwrap_or(false)
        {
            out.extend(load_cases_file(&p)?);
        }
    }
    out.sort_by(|a, b| a.id.cmp(&b.id));
    Ok(out)
}

/// Score parsed steps against expectations. `parsed` is one [`ParsedExpr`] per step.
///
/// When `final_step_source` is provided, it should be the concatenation of the successful plan’s
/// step `text` fields (same surface the LLM produced), used only for [`ExpectBlock::step_text_contains_any`].
pub fn score_case(
    expect: &ExpectBlock,
    parsed: &[ParsedExpr],
    final_step_source: Option<&str>,
) -> CaseScore {
    let mut notes = Vec::new();
    let n = parsed.len();
    let step_count_ok = expect.min_steps.map(|m| n >= m).unwrap_or(true)
        && expect.max_steps.map(|m| n <= m).unwrap_or(true);
    if !step_count_ok {
        notes.push(format!(
            "step count {n} vs min {:?} max {:?}",
            expect.min_steps, expect.max_steps
        ));
    }

    let mut entities: HashSet<String> = HashSet::new();
    let mut pred_fields: HashSet<String> = HashSet::new();
    let mut pred_values: HashSet<String> = HashSet::new();
    let mut chains: HashSet<String> = HashSet::new();
    let mut projections: Vec<Vec<String>> = Vec::new();

    for p in parsed {
        collect_expr(
            &p.expr,
            &mut entities,
            &mut pred_fields,
            &mut pred_values,
            &mut chains,
        );
        if let Some(proj) = &p.projection {
            projections.push(proj.clone());
        }
    }

    let entity_match =
        expect.entities_any.is_empty() || expect.entities_any.iter().any(|e| entities.contains(e));

    let pred_fields_match = expect.pred_fields_any.is_empty()
        || expect
            .pred_fields_any
            .iter()
            .all(|f| pred_fields.contains(f));

    let pred_values_match = expect.pred_values_any.is_empty()
        || expect
            .pred_values_any
            .iter()
            .any(|v| pred_values.iter().any(|pv| pv.contains(v.as_str())));

    let chain_match = expect.chain_selectors_any.is_empty()
        || expect
            .chain_selectors_any
            .iter()
            .any(|c| chains.contains(c));

    let projection_match = expect.projection_contains.is_empty()
        || projections.iter().any(|proj| {
            expect
                .projection_contains
                .iter()
                .all(|need| proj.iter().any(|p| p == need))
        });

    if !entity_match {
        notes.push(format!(
            "entities got {:?} want any of {:?}",
            entities, expect.entities_any
        ));
    }
    if !pred_fields_match {
        notes.push(format!(
            "pred fields got {:?} need all of {:?}",
            pred_fields, expect.pred_fields_any
        ));
    }

    let step_text_ok = expect.step_text_contains_any.is_empty()
        || final_step_source.is_some_and(|src| {
            expect
                .step_text_contains_any
                .iter()
                .any(|needle| src.contains(needle.as_str()))
        });
    if !expect.step_text_contains_any.is_empty() && !step_text_ok {
        notes.push(format!(
            "step_text_contains_any: surface text missing all of {:?}",
            expect.step_text_contains_any
        ));
    }

    let steps_ok = step_count_ok && step_text_ok;

    let weights = [
        (entity_match, 0.25_f32),
        (pred_fields_match, 0.2),
        (pred_values_match, 0.15),
        (chain_match, 0.15),
        (projection_match, 0.1),
        (steps_ok, 0.15_f32),
    ];
    let score: f32 = weights.iter().filter(|(ok, _)| *ok).map(|(_, w)| w).sum();

    CaseScore {
        id: String::new(),
        tags: vec![],
        goal: String::new(),
        reference_expr: None,
        attempt_trace: vec![],
        parse_ok: true,
        typecheck_ok: true,
        entity_match,
        pred_fields_match,
        pred_values_match,
        chain_match,
        projection_match,
        steps_ok,
        score,
        semantic_score: None,
        correction_pipeline_score: None,
        correction: None,
        notes,
    }
}

/// Semantic score when no valid parse/typecheck result exists.
pub fn failed_semantic_case_score() -> CaseScore {
    CaseScore {
        id: String::new(),
        tags: vec![],
        goal: String::new(),
        reference_expr: None,
        attempt_trace: vec![],
        parse_ok: false,
        typecheck_ok: false,
        entity_match: false,
        pred_fields_match: false,
        pred_values_match: false,
        chain_match: false,
        projection_match: false,
        steps_ok: false,
        score: 0.0,
        semantic_score: Some(0.0),
        correction_pipeline_score: None,
        correction: None,
        notes: vec![],
    }
}

/// Entity names referenced in an expression (Get/Query/Create/Delete/Invoke sources).
///
/// Used by `plasm-eval coverage` when combining `reference_expr` with `expect.entities_any`.
pub fn entities_from_expr(expr: &Expr) -> HashSet<String> {
    let mut entities = HashSet::new();
    let mut pred_fields = HashSet::new();
    let mut pred_values = HashSet::new();
    let mut chains = HashSet::new();
    collect_expr(
        expr,
        &mut entities,
        &mut pred_fields,
        &mut pred_values,
        &mut chains,
    );
    entities
}

/// Parse a Plasm expression against `cgs` and return entity names it references.
pub fn entities_from_reference_expr(
    reference_expr: &str,
    cgs: &CGS,
) -> Result<HashSet<String>, plasm_core::expr_parser::ParseError> {
    let pe = plasm_core::expr_parser::parse(reference_expr, cgs)?;
    Ok(entities_from_expr(&pe.expr))
}

/// Recursively collect all signals from an expression tree into the scoring sets.
///
/// - `entities`   : every entity touched (Get entity, Query entity, Chain source + target)
/// - `pred_fields`: all field names appearing in predicates
/// - `pred_values`: all values appearing in predicates **and** Get IDs
/// - `chains`     : relation selectors from `ChainExpr` nodes; also the selector
///   for cardinality-many navigation (which lowers to `QueryExpr`)
fn collect_expr(
    expr: &Expr,
    entities: &mut HashSet<String>,
    pred_fields: &mut HashSet<String>,
    pred_values: &mut HashSet<String>,
    chains: &mut HashSet<String>,
) {
    match expr {
        Expr::Get(g) => {
            entities.insert(g.reference.entity_type.to_string());
            // Values the LLM chose for the GET key — counts toward pred_values_any.
            match &g.reference.key {
                plasm_core::EntityKey::Simple(id) => {
                    pred_values.insert(id.to_string());
                }
                plasm_core::EntityKey::Compound(parts) => {
                    for v in parts.values() {
                        pred_values.insert(v.clone());
                    }
                }
            }
        }
        Expr::Query(q) => {
            entities.insert(q.entity.to_string());
            collect_predicate_info(q.predicate.as_ref(), pred_fields, pred_values);
        }
        Expr::Chain(c) => {
            // Record the selector: this satisfies chain_selectors_any regardless
            // of whether it's cardinality-one (stays as Chain) or many.
            chains.insert(c.selector.clone());
            // Recurse into source — collects the source entity + its id value.
            collect_expr(&c.source, entities, pred_fields, pred_values, chains);
            // The target entity is the terminal entity of the chain.
            // primary_entity() walks to the innermost source, so we need the
            // final output entity.  For AutoGet we don't know it without CGS,
            // but the primary_entity of the whole chain IS the source, so we
            // just make sure the source entity is registered (done in recursion).
            // Callers that need the target can use chain_selectors_any instead.
        }
        Expr::Delete(d) => {
            entities.insert(d.target.entity_type.to_string());
        }
        Expr::Invoke(i) => {
            entities.insert(i.target.entity_type.to_string());
        }
        Expr::Create(c) => {
            entities.insert(c.entity.to_string());
        }
        Expr::Page(_) => {}
    }
}

fn collect_predicate_info(
    pred: Option<&Predicate>,
    fields: &mut HashSet<String>,
    values: &mut HashSet<String>,
) {
    let Some(p) = pred else { return };
    walk_pred(p, fields, values);
}

fn walk_pred(p: &Predicate, fields: &mut HashSet<String>, values: &mut HashSet<String>) {
    match p {
        Predicate::True | Predicate::False => {}
        Predicate::Comparison { field, value, .. } => {
            fields.insert(field.clone());
            match value {
                plasm_core::Value::String(s) => {
                    values.insert(s.clone());
                }
                plasm_core::Value::Integer(i) => {
                    values.insert(i.to_string());
                }
                plasm_core::Value::Float(f) => {
                    values.insert(f.to_string());
                }
                plasm_core::Value::Bool(b) => {
                    values.insert(b.to_string());
                }
                _ => {}
            }
        }
        Predicate::And { args } | Predicate::Or { args } => {
            for a in args {
                walk_pred(a, fields, values);
            }
        }
        Predicate::Not { predicate } => walk_pred(predicate, fields, values),
        Predicate::ExistsRelation {
            predicate: inner, ..
        } => {
            if let Some(ib) = inner {
                walk_pred(ib, fields, values);
            }
        }
    }
}

/// Attach id/tags and parse/typecheck flags into score (single-attempt, no correction blend).
pub fn finalize_score(
    mut s: CaseScore,
    id: String,
    tags: Vec<String>,
    parse_ok: bool,
    typecheck_ok: bool,
) -> CaseScore {
    s.id = id;
    s.tags = tags;
    s.parse_ok = parse_ok;
    s.typecheck_ok = typecheck_ok;
    s.semantic_score = Some(s.score);
    if !parse_ok || !typecheck_ok {
        s.score *= 0.5;
    }
    s
}

/// Finalize score with optional correction metrics (multi-attempt eval).
///
/// When `correction` is `Some`, `score = semantic * (1 - w) + pipeline_score * w`.
/// When `None`, applies legacy `* 0.5` on parse/type failure.
pub fn finalize_case_score(
    mut s: CaseScore,
    id: String,
    tags: Vec<String>,
    parse_ok: bool,
    typecheck_ok: bool,
    correction: Option<CorrectionMetrics>,
    correction_weight: f32,
) -> CaseScore {
    s.id = id;
    s.tags = tags;
    s.parse_ok = parse_ok;
    s.typecheck_ok = typecheck_ok;
    let sem = s.score;
    s.semantic_score = Some(sem);

    if let Some(cm) = correction {
        s.correction = Some(cm.clone());
        let pipe = cm.pipeline_score;
        s.correction_pipeline_score = Some(pipe);
        let w = correction_weight.clamp(0.0, 1.0);
        s.score = sem * (1.0 - w) + pipe * w;
    } else if !parse_ok || !typecheck_ok {
        s.score *= 0.5;
    }
    s
}

pub fn typecheck_steps(cgs: &CGS, parsed: &[ParsedExpr]) -> Result<(), plasm_core::TypeError> {
    for p in parsed {
        type_check_expr(&p.expr, cgs)?;
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use plasm_core::expr_parser;
    use plasm_core::loader::load_schema_dir;
    use plasm_core::type_checker::type_check_expr as tc_expr;

    #[test]
    fn petstore_ps01_scores_on_golden_expr() {
        let dir = std::path::Path::new("../../fixtures/schemas/petstore");
        if !dir.exists() {
            return;
        }
        let cgs = load_schema_dir(dir).unwrap();
        let p = expr_parser::parse("Pet{status=available}", &cgs).unwrap();
        let ex = ExpectBlock {
            entities_any: vec!["Pet".into()],
            pred_fields_any: vec!["status".into()],
            pred_values_any: vec!["available".into()],
            ..Default::default()
        };
        let sc = score_case(&ex, std::slice::from_ref(&p), None);
        assert!(sc.entity_match);
        assert!(sc.pred_fields_match);
        assert!(sc.pred_values_match);
    }

    #[test]
    fn step_text_contains_any_requires_heredoc_opener_in_surface_text() {
        let dir = std::path::Path::new("../../fixtures/schemas/petstore");
        if !dir.exists() {
            return;
        }
        let cgs = load_schema_dir(dir).unwrap();
        let p = expr_parser::parse("Pet{status=available}", &cgs).unwrap();
        let ex = ExpectBlock {
            entities_any: vec!["Pet".into()],
            pred_fields_any: vec!["status".into()],
            pred_values_any: vec!["available".into()],
            step_text_contains_any: vec!["<<".into()],
            ..Default::default()
        };
        let bad = score_case(&ex, std::slice::from_ref(&p), Some("Pet{status=available}"));
        assert!(!bad.steps_ok);
        let good = score_case(
            &ex,
            std::slice::from_ref(&p),
            Some("Pet{status=<<S\navailable\nS\n}"),
        );
        assert!(good.steps_ok);
    }

    #[test]
    fn github_issue_update_and_comment_create_heredoc_reference_parse() {
        let dir = std::path::Path::new("../../apis/github");
        if !dir.exists() {
            return;
        }
        let cgs = load_schema_dir(dir).unwrap();
        let update = concat!(
            "Issue(owner=\"plasm\",repo=\"plasm\",number=7).update(body=<<U\n",
            "## Notes\n\n- one\n",
            "U\n",
            ")",
        );
        let p1 = expr_parser::parse(update, &cgs).unwrap();
        tc_expr(&p1.expr, &cgs).unwrap();

        let create = concat!(
            "IssueComment.issue-comment-create(repository=Repository(owner=\"plasm\",repo=\"plasm\"),",
            "issue_number=99,body=<<C\n## Triage\n\nPlease see below.\nC\n",
            ")",
        );
        let p2 = expr_parser::parse(create, &cgs).unwrap();
        tc_expr(&p2.expr, &cgs).unwrap();
    }

    #[test]
    fn finalize_case_score_blends_semantic_and_pipeline() {
        let mut sc = CaseScore {
            id: String::new(),
            tags: vec![],
            goal: String::new(),
            reference_expr: None,
            attempt_trace: vec![],
            parse_ok: true,
            typecheck_ok: true,
            entity_match: true,
            pred_fields_match: true,
            pred_values_match: true,
            chain_match: true,
            projection_match: true,
            steps_ok: true,
            score: 0.8,
            semantic_score: None,
            correction_pipeline_score: None,
            correction: None,
            notes: vec![],
        };
        let cm = crate::build_correction_metrics(2, Some(1), true, None);
        let pipe = cm.pipeline_score;
        sc = finalize_case_score(sc, "t".into(), vec![], true, true, Some(cm), 0.25);
        let expected = 0.8 * 0.75 + pipe * 0.25;
        assert!((sc.score - expected).abs() < 1e-5);
        assert!(sc.correction.is_some());
        assert!(sc.correction.as_ref().unwrap().recovered);
    }
}
